#!/usr/bin/env python3
import sys
import os
import json

# 添加技能路径
sys.path.append('skills/finance/scripts')

# 导入sql_query模块
try:
    from sql_query import run_sql_query
except ImportError as e:
    print(f"导入失败: {e}")
    sys.exit(1)

def main():
    """检查表结构"""

    # 查询表结构
    queries = [
        "SELECT column_name, data_type FROM information_schema.columns WHERE table_name = 'cost_database' ORDER BY ordinal_position",
        "SELECT column_name, data_type FROM information_schema.columns WHERE table_name = 'cc_mapping' ORDER BY ordinal_position",
        "SELECT DISTINCT business_line FROM cc_mapping LIMIT 20",
        "SELECT DISTINCT function FROM cost_database WHERE function ILIKE '%IT%' OR function ILIKE '%信息%' OR function ILIKE '%技术%' LIMIT 20"
    ]

    for i, query in enumerate(queries):
        print(f"\n查询 {i+1}:")
        print("="*60)
        print(query)
        print("-"*60)

        result = run_sql_query(query)

        try:
            data = json.loads(result)
            if "rows" in data:
                rows = data["rows"]
                for row in rows:
                    print(row)
            else:
                print(f"结果: {result}")
        except json.JSONDecodeError:
            print(f"结果: {result}")

if __name__ == "__main__":
    main()

